scwin.sbm_retrieve_submitdone = async function (e) {
  // <!--  조회 TR EVENT(성공) --> 
  //
  // for=ds_results event=OnLoadCompleted(rowCnt)
  var rowCnt = ds_reuslts.getTotalRow();
  if (rowCnt < 1) {
    totalRows.setValue(rowCnt); //cfShowTotalRows(totalRows, 0); 총건수 표시
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    return;
  }
  var rowCnt_val = 0;
  totalRows.setValue(rowCnt);
  for (var i = 0; i < ds_reuslts.getTotalRow(); i++) {
    if (ds_reuslts.getCellData(i, "vehclCnt") > 0) {
      gr_results.setCellStyle(i, "vehclCnt", "text-decoration", "underline");
    }
    if (ds_reuslts.getCellData(i, "mntrCnt") > 0) {
      gr_results.setCellStyle(i, "mntrCnt", "text-decoration", "underline");
    }
    if (ds_reuslts.getCellData(i, "notMntrCnt") > 0) {
      gr_results.setCellStyle(i, "notMntrCnt", "text-decoration", "underline");
    }
  }
};
scwin.sbm_retrieve_Detail_submitdone = async function (e) {
  // for=ds_reuslts_detail event=OnLoadCompleted(rowCnt)
  var rowCnt = ds_reuslts_detail.getTotalRow();
  if (rowCnt < 1) {
    totalRows_detail.setValue("0");
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    return;
  }
  var dupCnt = 0;
  for (var i = 0; i < rowCnt; i++) {
    for (var j = i + 1; j < rowCnt; j++) {
      // ASIS: for(var j=i+1; j<=rowCnt; j++){
      if (ds_reuslts_detail.getCellData(i, "transWrkIndictNo") == ds_reuslts_detail.getCellData(j, "transWrkIndictNo")) {
        dupCnt++;
        i = j;
      }
    }
  }
  totalRows_detail.setValue(rowCnt - dupCnt);
};
